```class Solution {
    public int[] gardenNoAdj(int n, int[][] paths) {
        int[] result = new int[n];
        for (int i = 0; i < n; i++) {
            int count = 0;
            for (int[] path : paths) {
                if (path[0] == i) {
                    count++;
                }
                if (path[1] == i) {
                    count++;
                }
            }
            result[i] = count;
        }
        return result;
    }
}
